    40→// ═══════════════════════════════════════════════════════════════
    41→// WEBSOCKET BRIDGE — connects Claude Code ↔ ClawCraft UI
    42→// Port 9477, JSON protocol
    43→// ═══════════════════════════════════════════════════════════════
    44→function startBridge() {
    45→  wss = new WebSocketServer({ port: BRIDGE_PORT });
    46→  console.log(`[Bridge] WebSocket server listening on ws://localhost:${BRIDGE_PORT}`);
    47→
    48→  wss.on('connection', (ws) => {
    49→    console.log('[Bridge] Client connected');
    50→    ws.send(JSON.stringify({ type: 'connected', message: 'ClawCraft bridge ready' }));
    51→
    52→    // Forward orchestrator events to bridge clients
    53→    const forwardEvent = (event) => {
    54→      if (ws.readyState === 1) {
    55→        ws.send(JSON.stringify({ type: 'event', event }));
    56→      }
    57→    };
    58→    orchestrator.on('event', forwardEvent);
    59→
    60→    ws.on('message', async (raw) => {
    61→      let msg;
    62→      try { msg = JSON.parse(raw); } catch { ws.send(JSON.stringify({ type: 'error', error: 'invalid JSON' })); return; }
    63→
    64→      try {
    65→        let result;
    66→        switch (msg.action) {
    67→          case 'getState':
    68→            result = orchestrator.getState();
    69→            break;
    70→          case 'createAgent':
    71→            result = orchestrator.createAgent(msg.payload || {});
    72→            break;
    73→          case 'removeAgent':
    74→            result = await orchestrator.removeAgent(msg.agentId);
    75→            break;
    76→          case 'startRun':
    77→            result = await orchestrator.startRun(msg.payload || {});
    78→            break;
    79→          case 'cancelRun':
    80→            result = await orchestrator.cancelRun(msg.runId);
    81→            break;
    82→          case 'startRelay':
    83→            result = await orchestrator.startRelay(msg.payload || {});
    84→            break;
    85→          case 'getDiff':
    86→            result = orchestrator.getAgentDiff(msg.agentId);
    87→            break;
    88→          case 'listAgents':
    89→            result = orchestrator.listAgents();
    90→            break;
    91→          default:
    92→            result = { error: `Unknown action: ${msg.action}` };
    93→        }
    94→        ws.send(JSON.stringify({ type: 'response', id: msg.id, result }));
    95→      } catch (err) {
    96→        ws.send(JSON.stringify({ type: 'error', id: msg.id, error: err.message }));
    97→      }
    98→    });
    99→
   100→    ws.on('close', () => {
   101→      console.log('[Bridge] Client disconnected');
   102→      orchestrator.removeListener('event', forwardEvent);
   103→    });
   104→  });
   105→}
