{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_019B9xw2ZgB8qm7FGAgD6ytp","type":"tool_result","content":"     1→const { EventEmitter } = require('events');
     2→const { spawn } = require('child_process');
     3→const path = require('path');
     4→const readline = require('readline');
     5→
     6→const { RunStore } = require('./run-store');
     7→const { WorkspaceManager } = require('./workspace-manager');
     8→const { CodexAdapter } = require('../engines/codex-adapter');
     9→const { ClaudeAdapter } = require('../engines/claude-adapter');
    10→const { GeminiAdapter } = require('../engines/gemini-adapter');
    11→
    12→const PHASE_LIMITS = {
    13→  queued: 0.04,
    14→  planning: 0.18,
    15→  coding: 0.82,
    16→  testing: 0.92,
    17→  summarizing: 0.97,
    18→  done: 1,
    19→};
    20→
    21→class AgentOrchestrator extends EventEmitter {
    22→  constructor(projectRoot) {
    23→    super();
    24→    this.projectRoot = projectRoot;
    25→    this.workspaceManager = new WorkspaceManager(this.projectRoot);
    26→    this.runStore = new RunStore(path.join(this.projectRoot, '.clawcraft', 'runs'));
    27→    this.adapters = new Map([
    28→      ['codex', new CodexAdapter()],
    29→      ['claude', new ClaudeAdapter()],
    30→      ['gemini', new GeminiAdapter()],
    31→    ]);
    32→    this.agents = new Map();
    33→    this.activeRuns = new Map();
    34→    this.agentsFile = path.join(this.projectRoot, '.clawcraft', 'agents.json');
    35→    // Restore agents from previous session, then clean orphans
    36→    this._restoreAgents();
    37→    const knownIds = new Set(this.agents.keys());
    38→    this.workspaceManager.cleanupOrphanWorktrees(knownIds);
    39→  }
    40→
    41→  _restoreAgents() {
    42→    const fs = require('fs');
    43→    if (!fs.existsSync(this.agentsFile)) return;
    44→    try {
    45→      const data = JSON.parse(fs.readFileSync(this.agentsFile, 'utf8'));
    46→      for (const agent of data) {
    47→        agent.status = 'idle';
    48→        agent.currentRunId = null;
    49→        this.agents.set(String(agent.id), agent);
    50→      }
    51→    } catch {}
    52→  }
    53→
    54→  _persistAgents() {
    55→    const fs = require('fs');
    56→    const data = [...this.agents.values()].map(a => ({
    57→      id: a.id, name: a.name, engine: a.engine, model: a.model, role: a.role,
    58→    }));
    59→    fs.writeFileSync(this.agentsFile, JSON.stringify(data, null, 2));
    60→  }
    61→
    62→  listAgents() {
    63→    return [...this.agents.values()];
    64→  }
    65→
    66→  getEngineStatuses() {
    67→    return [...this.adapters.values()].map((adapter) => adapter.describe());
    68→  }
    69→
    70→  getState() {
    71→    return {
    72→      agents: this.listAgents(),
    73→      runs: this.runStore.listRuns(),
    74→      engines: this.getEngineStatuses(),
    75→      liveMode: true,
    76→      parallelMode: 'git-worktree',
    77→      collaborationModes: ['solo', 'shared-brief', 'relay'],
    78→    };
    79→  }
    80→
    81→  // 4단계: Relay mode — chain agents sequentially, each gets previous output
    82→  async startRelay(payload) {
    83→    const { agentIds, prompt, taskTitle } = payload;
    84→    if (!agentIds || agentIds.length < 2) throw new Error('Relay에는 2개 이상의 에이전트가 필요합니다.');
    85→    const results = [];
    86→    let currentPrompt = prompt;
    87→    for (const agentId of agentIds) {
    88→      const agent = this.agents.get(String(agentId));
    89→      if (!agent) { results.push({ agentId, status: 'skipped', error: 'agent not found' }); continue; }
    90→      try {
    91→        const run = await this.startRun({ agentId: String(agentId), prompt: currentPrompt, taskTitle });
    92→        // Wait for run to complete
    93→        await new Promise((resolve, reject) => {
    94→          const handler = (event) => {
    95→            const eid = event.run?.id || event.runId;
    96→            if (eid !== run.id) return;
    97→            if (event.type === 'run.completed') { this.removeListener('event', handler); resolve(event); }
    98→            if (event.type === 'run.failed') { this.removeListener('event', handler); reject(new Error(event.errorText || 'failed')); }
    99→            if (event.type === 'run.cancelled') { this.removeListener('event', handler); reject(new Error('cancelled')); }
   100→          };
   101→          this.on('event', handler);
   102→        });
   103→        const finishedRun = this.runStore.getRun(run.id);
   104→        const summary = finishedRun?.summary || '';
   105→        results.push({ agentId, status: 'done', summary });
   106→        // Next agent gets previous agent's output as context
   107→        currentPrompt = `## Previous Agent Output (${agent.name})\n${summary}\n\n---\n\n## Task\n${prompt}`;
   108→      } catch (err) {
   109→        results.push({ agentId, status: 'failed', error: err.message });
   110→        break; // Stop relay chain on failure
   111→      }
   112→    }
   113→    return results;
   114→  }
   115→
   116→  createAgent(payload = {}) {
   117→    const id = payload.id ?? `${Date.now()}`;
   118→    const engine = payload.engine || 'codex';
   119→    const adapter = this.adapters.get(engine);
   120→
   121→    // Create worktree for this agent
   122→    const workspace = this.workspaceManager.createWorktree(String(id));
   123→
   124→    const agent = {
   125→      id,
   126→      name: payload.name || `Agent-${id}`,
   127→      engine,
   128→      model: payload.model || (engine === 'claude' ? 'default' : 'gpt-5'),
   129→      role: payload.role || 'builder',
   130→      status: 'idle',
   131→      currentRunId: null,
   132→      available: adapter ? adapter.isAvailable() : false,
   133→      workspace, // { workdir, strategy, branch }
   134→    };
   135→    this.agents.set(String(id), agent);
   136→    this._persistAgents();
   137→    this.emitEvent({ type: 'agent.created', agent });
   138→    return agent;
   139→  }
   140→
   141→  async removeAgent(agentId) {
   142→    const key = String(agentId);
   143→    const agent = this.agents.get(key);
   144→    if (!agent) return { ok: true };
   145→    if (agent.currentRunId) {
   146→      await this.cancelRun(agent.currentRunId, true); // wait for process exit
   147→    }
   148→    // Clean up worktree after process is confirmed dead
   149→    this.workspaceManager.removeWorktree(key);
   150→    this.agents.delete(key);"}]},"parent_tool_use_id":"toolu_01MjmguMqEDaffcqf1CRFgoS","session_id":"5d18d7b1-501e-4d80-b03f-23201afdf085","uuid":"40e42668-587a-4238-9e3e-df3a837c9249"}

